const{SlashCommandBuilder:SlashCommandBuilder,EmbedBuilder:EmbedBuilder}=require("discord.js"),fetch=require("node-fetch"),config=require("../config");class CollectionCommand{constructor(){}getCommandData(){return(new SlashCommandBuilder).setName("collection").setDescription("Shows overview of OpenSea collection by slug").addStringOption((option=>option.setName("slug").setDescription("Collection slug (e.g. tiny-buds40x40)").setRequired(!0))).addStringOption((option=>option.setName("chain").setDescription("Blockchain network").setRequired(!1).addChoices({name:"Base",value:"base"},{name:"Ethereum",value:"ethereum"},{name:"Polygon",value:"polygon"},{name:"Arbitrum",value:"arbitrum"},{name:"Optimism",value:"optimism"})))}async execute(interaction){try{const slug=interaction.options.getString("slug",!0),chain=interaction.options.getString("chain")||"base";console.log(`🔍 Collection command executed for: ${slug} on ${chain}`),await interaction.deferReply();const colRes=await fetch(`https://api.opensea.io/api/v2/collections/${encodeURIComponent(slug)}?chain=${chain}`,{headers:{Accept:"application/json","X-API-KEY":config.opensea.apiKey}});if(!colRes.ok)throw new Error(`Get Collection failed: ${colRes.status} ${colRes.statusText}`);const collection=await colRes.json(),statsRes=await fetch(`https://api.opensea.io/api/v2/collections/${encodeURIComponent(slug)}/stats?chain=${chain}`,{headers:{Accept:"application/json","X-API-KEY":config.opensea.apiKey}});if(!statsRes.ok)throw new Error(`Get Collection Stats failed: ${statsRes.status} ${statsRes.statusText}`);const stats=await statsRes.json(),name=collection?.name??slug,createdDate=collection?.created_date??null,totalSupply=collection?.total_supply??null,description=collection?.description??null,fees=Array.isArray(collection?.fees)?collection.fees:[],creatorFees=fees.filter((f=>f&&f.recipient&&!1===f.required)),floor=(fees.filter((f=>f&&!0===f.required)),stats?.total?.floor_price??null),totalVolume=stats?.total?.volume??null,totalSales=stats?.total?.sales??null,holders=stats?.total?.num_owners??null,marketCap=stats?.total?.market_cap??null,averagePrice=stats?.total?.average_price??null,intervals=stats?.intervals??[],oneDay=intervals.find((i=>"one_day"===i.interval)),sevenDay=intervals.find((i=>"seven_day"===i.interval)),thirtyDay=intervals.find((i=>"thirty_day"===i.interval)),fmt=n=>null==n?"—":"number"==typeof n?n>=1e6?`${(n/1e6).toFixed(2)}M`:n>=1e3?`${(n/1e3).toFixed(2)}K`:n.toLocaleString("en-US",{maximumFractionDigits:4}):"—",fmtEth=n=>null==n?"—":"number"==typeof n?`${n.toFixed(2)} ETH`:"—",feeList=arr=>arr.length?arr.map((f=>`${"number"==typeof f.fee?f.fee:"—"}% (${f.required?"enforced":"optional"})`)).join("\n"):"—",embed=(new EmbedBuilder).setTitle(`📊 ${name}`).setURL(`https://opensea.io/collection/${slug}`).setColor(65416);if(description){const shortDesc=description.length>1024?description.substring(0,1021)+"...":description;embed.setDescription(shortDesc)}embed.addFields({name:"🎯 Floor Price",value:fmtEth(floor),inline:!0},{name:"🪙 Creators Fee",value:feeList(creatorFees),inline:!0},{name:"🔢 Total Supply",value:fmt(totalSupply),inline:!0}),embed.addFields({name:"📊 Average Price",value:fmtEth(averagePrice),inline:!0},{name:"👥 Unique Holders",value:fmt(holders),inline:!0},{name:"🔷 Chain",value:chain.toUpperCase(),inline:!0}),embed.addFields({name:"📈 Total Volume",value:`${fmtEth(totalVolume)} (${fmt(totalSales)} sales)`,inline:!0},{name:"💎 Market Cap",value:fmtEth(marketCap),inline:!0},{name:"📅 Created",value:createdDate||"—",inline:!0}),embed.addFields({name:"⏰ Volume",value:`1d: ${fmtEth(oneDay?.volume)} (${fmt(oneDay?.sales)} sales)\n7d: ${fmtEth(sevenDay?.volume)} (${fmt(sevenDay?.sales)} sales)\n30d: ${fmtEth(thirtyDay?.volume)} (${fmt(thirtyDay?.sales)} sales)`,inline:!1}),embed.setFooter({text:`Source: OpenSea API v2 • /collection ${slug}`}).setTimestamp(),collection?.image_url&&embed.setThumbnail(collection.image_url);const socialLinks=[];collection?.project_url&&socialLinks.push(`[🌐 Website](${collection.project_url})`),collection?.twitter_username&&socialLinks.push(`[🐦 Twitter](https://twitter.com/${collection.twitter_username})`),collection?.discord_url&&socialLinks.push(`[🎮 Discord](${collection.discord_url})`),socialLinks.length>0&&embed.addFields({name:"🔗 Social Links",value:socialLinks.join(" • "),inline:!1}),await interaction.editReply({embeds:[embed]})}catch(error){console.error("❌ Error in collection command:",error);let errorMessage="❌ An error occurred while loading collection information.";error.message.includes("rate limit")||error.message.includes("429")?errorMessage="⚠️ OpenSea API rate limit reached. Please try again later.":error.message.includes("404")||error.message.includes("not found")?errorMessage="❌ Collection not found. Please check the collection name.":(error.message.includes("401")||error.message.includes("unauthorized"))&&(errorMessage="❌ OpenSea API authentication error. Please check your API key."),await interaction.editReply({content:errorMessage})}}async disconnect(){}}module.exports=CollectionCommand;